    40→export const generateSolution = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
    41→  const apiKey = getApiKey();
    42→  
    43→  // Check if API Key is available
    44→  if (!apiKey) {
    45→    console.warn("API_KEY not found or process.env unavailable, using simulation.");
    46→    return fallbackSimulation(rec, url);
    47→  }
    48→
    49→  try {
    50→    const ai = new GoogleGenAI({ apiKey });
    51→    
    52→    // Schema strict pour garantir la structure de la réponse avec les étapes
    53→    const schema: Schema = {
    54→      type: Type.OBJECT,
    55→      properties: {
    56→        title: { type: Type.STRING, description: "Titre technique de la solution" },
    57→        explanation: { type: Type.STRING, description: "Pourquoi cette modif améliore la citation IA (max 2 phrases)" },
    58→        type: { type: Type.STRING, enum: ["code", "text"], description: "Format de la solution" },
    59→        language: { type: Type.STRING, enum: ["html", "json", "text", "css", "javascript"], description: "Langage utilisé" },
    60→        content: { type: Type.STRING, description: "Le code complet ou le contenu textuel. S'il y a plusieurs fichiers, sépare-les clairement." },
    61→        implementationSteps: {
    62→            type: Type.ARRAY,
    63→            items: { type: Type.STRING },
    64→            description: "Guide tutoriel ultra-détaillé pour débutant (ex: '1. Ouvrez votre admin WordPress', '2. Allez dans Apparence > Éditeur')."
    65→        }
    66→      },
    67→      required: ["title", "explanation", "type", "content", "implementationSteps"],
    68→    };
    69→
    70→    const prompt = `
    71→      CONTEXTE :
    72→      Tu es l'IA principale de CitedBy.ai, experte en Webmastering et Pédagogie pour débutants.
    73→      Le client souhaite corriger un problème sur son site : ${url}
    74→      
    75→      PROBLÈME DÉTECTÉ : ${rec.title}
    76→      ACTION REQUISE : ${rec.action}
    77→
    78→      TA MISSION :
    79→      Génère un KIT DE SOLUTION COMPLET pour un DEBUTANT absolu.
    80→      
    81→      1. **CODE / CONTENU** : Fournis l'intégralité du code nécessaire (HTML, CSS, JS, JSON-LD).
    82→         - Si plusieurs fichiers ou snippets sont requis, sépare-les clairement par des commentaires en majuscules (ex: <!-- PARTIE 1 : HTML -->, /* PARTIE 2 : CSS */).
    83→         - Le code doit être prêt à copier-coller (pas de placeholders "insérez ici" si possible, remplis avec des exemples pertinents basés sur l'URL).
    84→      
    85→      2. **GUIDE D'INSTALLATION (PAS À PAS)** :
    86→         - Imagine que tu parles à quelqu'un qui n'a jamais codé.
    87→         - Explique exactement où cliquer dans un CMS standard (WordPress, Shopify) ou où placer le fichier.
    88→         - Utilise un langage simple, sans jargon technique complexe non expliqué.
    89→         - Numérote les étapes clairement (Étape 1, Étape 2...).
    90→
    91→      CRITÈRES AEO À RESPECTER DANS LA SOLUTION :
    92→      - Answer-First (Réponse directe).
    93→      - Données Structurées (JSON-LD).
    94→      - Sémantique HTML5.
    95→
    96→      Réponds uniquement au format JSON strict selon le schéma fourni.
    97→    `;
    98→
    99→    const response = await ai.models.generateContent({
   100→      model: 'gemini-3-flash-preview',
   101→      contents: prompt,
   102→      config: {
   103→        responseMimeType: 'application/json',
   104→        responseSchema: schema,
   105→        temperature: 0.2,
   106→      }
   107→    });
   108→
   109→    let output = response.text;
   110→    if (!output) {
   111→      throw new Error("Empty response from AI");
   112→    }
   113→
   114→    // Clean up potentially leaked markdown fences despite JSON mode
   115→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
   116→
   117→    const jsonResponse = JSON.parse(output);
   118→    
   119→    return {
   120→      title: jsonResponse.title,
   121→      explanation: jsonResponse.explanation,
   122→      type: jsonResponse.type as 'code' | 'text',
   123→      language: (jsonResponse.language as any) || 'text',
   124→      content: jsonResponse.content,
   125→      implementationSteps: jsonResponse.implementationSteps || ["Consultez un expert pour l'implémentation."]
   126→    };
   127→
   128→  } catch (error) {
   129→    console.error("AI Generation failed:", error);
   130→    return fallbackSimulation(rec, url);
   131→  }
   132→};
